// Busca os dados diretamente do Error Trigger, ignorando o output do SQL
const errorData = $('Error Trigger').first().json;

const executionId = errorData?.execution?.id || $execution.id || 'N/A';

const mode = errorData?.execution?.mode || 'Test';
const workflowName = errorData?.workflow?.name || 'Metal Rates';

const errorMessage = errorData?.error?.message || 
                     errorData?.error?.description || 
                     JSON.stringify(errorData?.error) || 
                     'Menssagio di errore non disponibile';

const errorNode = errorData?.error?.node?.name || 
                  errorData?.error?.context?.nodeName || 
                  'Node non identificato';

const errorStack = errorData?.error?.stack || 'Stack trace non disponibile';

const errorType = errorData?.error?.name || 
                  errorData?.error?.type || 
                  'Tipo sconosciuto';

const timestamp = new Date().toLocaleString('pt-IT', { timeZone: 'Europe/Rome' });

// Sanitiza para uso seguro em SQL (escapa aspas simples)
const sanitize = (str) => String(str || '').replace(/'/g, "''").substring(0, 2000);

return [{
  json: {
    executionId,
    mode,
    workflowName,
    errorMessage: sanitize(errorMessage),   // já sanitizado
    errorNode:    sanitize(errorNode),       // já sanitizado
    errorStack,
    errorType,
    timestamp,
    rawDump: JSON.stringify(errorData, null, 2)
  }
}];

